import React from 'react';

const tareas = [
  { text:"Estudiar programación", completed:false },
  { text:"Leer", completed:false },
  { text:"Ir a tirar", completed:false }
]

function App() {
  return (
    <React.Fragment>
      <CheckCounter />
      <h2>Completaste 2 de 3 tareas.</h2>
      <CheckSearch />
      <input placeholder="Buscar tarea..." />
      <CheckList>
        {tareas.map(() => (
          <CheckItem />
        ))}
      </CheckList>
      <CreateCheckButton />
      <button>+</button>
    </React.Fragment>
  );
}

export default App;
